#include "hirct/Target/GenWrapper.h"

#include "hirct/Analysis/IRAnalysis.h"

#include <algorithm>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iostream>
#include <map>
#include <memory>
#include <sstream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

namespace {

struct TrieNode {
  std::map<std::string, std::unique_ptr<TrieNode>> children;
  std::vector<PortView> leaf_ports;
};

std::vector<std::string> split_tokens(const std::string &name) {
  std::vector<std::string> tokens;
  std::istringstream iss(name);
  std::string tok;
  while (std::getline(iss, tok, '_')) {
    if (!tok.empty())
      tokens.push_back(tok);
  }
  return tokens;
}

void collect_all_ports(const TrieNode *node, std::vector<PortView> &out) {
  for (const auto &p : node->leaf_ports)
    out.push_back(p);
  for (const auto &kv : node->children)
    collect_all_ports(kv.second.get(), out);
}

bool has_sub_branch(const TrieNode *node) {
  const TrieNode *cur = node;
  while (cur->children.size() == 1 && cur->leaf_ports.empty())
    cur = cur->children.begin()->second.get();
  return cur->children.size() >= 2;
}

void find_groups(const TrieNode *node, const std::string &prefix, int depth,
                 int max_depth,
                 std::map<std::string, std::vector<PortView>> &groups) {
  const TrieNode *cur = node;
  std::string cur_prefix = prefix;

  while (cur->children.size() == 1 && cur->leaf_ports.empty()) {
    const auto &entry = *cur->children.begin();
    cur_prefix =
        cur_prefix.empty() ? entry.first : cur_prefix + "_" + entry.first;
    cur = entry.second.get();
  }

  if (cur->children.empty()) {
    for (const auto &p : cur->leaf_ports)
      groups[""].push_back(p);
    return;
  }

  bool has_real_groups = false;
  std::vector<PortView> local_ungrouped;

  for (const auto &p : cur->leaf_ports)
    local_ungrouped.push_back(p);

  for (const auto &kv : cur->children) {
    std::string child_prefix =
        cur_prefix.empty() ? kv.first : cur_prefix + "_" + kv.first;
    std::vector<PortView> subtree_ports;
    collect_all_ports(kv.second.get(), subtree_ports);

    if (subtree_ports.size() < 2) {
      for (auto &p : subtree_ports)
        local_ungrouped.push_back(p);
    } else if (depth + 1 < max_depth && has_sub_branch(kv.second.get())) {
      find_groups(kv.second.get(), child_prefix, depth + 1, max_depth, groups);
      has_real_groups = true;
    } else {
      groups[child_prefix] = std::move(subtree_ports);
      has_real_groups = true;
    }
  }

  if (!has_real_groups && local_ungrouped.size() >= 2 && !cur_prefix.empty()) {
    groups[cur_prefix] = std::move(local_ungrouped);
  } else {
    for (auto &p : local_ungrouped)
      groups[""].push_back(p);
  }
}

std::map<std::string, std::vector<PortView>>
group_ports_by_prefix(circt::hw::HWModuleOp module) {
  static constexpr int kMaxDepth = 2;

  std::vector<PortView> ports;
  for (auto pv : get_ports(module)) {
    if (is_clock_port(pv.name) || is_reset_port(pv.name))
      continue;
    ports.push_back(std::move(pv));
  }

  auto root = std::make_unique<TrieNode>();
  for (const auto &p : ports) {
    auto tokens = split_tokens(p.name);
    if (tokens.empty())
      continue;
    TrieNode *cur = root.get();
    for (const auto &tok : tokens) {
      auto &child = cur->children[tok];
      if (!child)
        child = std::make_unique<TrieNode>();
      cur = child.get();
    }
    cur->leaf_ports.push_back(p);
  }

  std::map<std::string, std::vector<PortView>> groups;
  find_groups(root.get(), "", 0, kMaxDepth, groups);

  std::map<std::string, size_t> port_order;
  for (size_t i = 0; i < ports.size(); ++i)
    port_order[ports[i].name] = i;

  for (auto &kv : groups) {
    std::sort(kv.second.begin(), kv.second.end(),
              [&port_order](const PortView &a, const PortView &b) {
                return port_order.at(a.name) < port_order.at(b.name);
              });
  }

  return groups;
}

} // namespace

GenWrapper::GenWrapper(circt::hw::HWModuleOp hw_module)
    : hw_module_(hw_module) {}

bool GenWrapper::emit(const std::string &output_dir) {
  std::string wrapper_dir = output_dir + "/wrapper";
  if (mkdir(wrapper_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenWrapper: cannot create directory: " << wrapper_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  std::string name = hw_module_.getSymName().str();
  std::string path = wrapper_dir + "/" + name + "_wrapper.sv";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenWrapper: cannot open " << path << "\n";
    return false;
  }

  auto groups = group_ports_by_prefix(hw_module_);

  ofs << AUTO_GENERATED_HEADER;
  ofs << "interface " << name << "_wrapper;\n\n";

  auto emit_logic_decl = [](std::ofstream &os, const PortView &p) {
    if (p.width == 0) {
      std::cerr << "GenWrapper: invalid width " << p.width << " for port "
                << p.name << ", skipping\n";
      return;
    }
    if (p.width == 1)
      os << "  logic        " << p.name << ";\n";
    else
      os << "  logic [" << (p.width - 1) << ":0] " << p.name << ";\n";
  };

  ofs << "/* verilator lint_off UNUSEDSIGNAL */\n";

  for (const auto &[prefix, ports] : groups) {
    if (prefix.empty())
      continue;
    ofs << "  // Group: " << prefix << "\n";
    for (const auto &p : ports)
      emit_logic_decl(ofs, p);
    ofs << "\n";
  }

  auto ungrouped_it = groups.find("");
  if (ungrouped_it != groups.end() && !ungrouped_it->second.empty()) {
    ofs << "  // Ungrouped\n";
    for (const auto &p : ungrouped_it->second)
      emit_logic_decl(ofs, p);
    ofs << "\n";
  }

  ofs << "/* verilator lint_on UNUSEDSIGNAL */\n";

  // Collect all ports (clock/reset already excluded) in stable order for
  // modports
  std::vector<const PortView *> all_ports;
  for (const auto &[prefix, ports] : groups) {
    if (prefix.empty())
      continue;
    for (const auto &p : ports)
      all_ports.push_back(&p);
  }
  if (ungrouped_it != groups.end()) {
    for (const auto &p : ungrouped_it->second)
      all_ports.push_back(&p);
  }

  // modport dut — same directions as the module
  if (!all_ports.empty()) {
    ofs << "  modport dut(\n";
    for (size_t i = 0; i < all_ports.size(); ++i) {
      const auto *p = all_ports[i];
      std::string dir_kw = p->is_input ? "input " : "output";
      ofs << "    " << dir_kw << " " << p->name;
      if (i + 1 < all_ports.size())
        ofs << ",";
      ofs << "\n";
    }
    ofs << "  );\n\n";

    // modport tb — reversed directions
    ofs << "  modport tb(\n";
    for (size_t i = 0; i < all_ports.size(); ++i) {
      const auto *p = all_ports[i];
      std::string dir_kw = p->is_input ? "output" : "input ";
      ofs << "    " << dir_kw << " " << p->name;
      if (i + 1 < all_ports.size())
        ofs << ",";
      ofs << "\n";
    }
    ofs << "  );\n\n";
  }

  ofs << "endinterface\n";
  ofs << "\n";
  ofs << "// Dummy module for lint (interface binding)\n";
  ofs << "/* verilator lint_off DECLFILENAME */\n";
  ofs << "module " << name << "_wrapper_bind();\n";
  ofs << "  " << name << "_wrapper intf();\n";
  ofs << "endmodule\n";
  ofs << "/* verilator lint_on DECLFILENAME */\n";
  return true;
}

} // namespace hirct
